module div_8bit
(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output reg [15:0] result
);
    reg [8:0] shift_reg;
    reg [8:0] neg_divisor;
    reg [7:0] quotient;
    reg [7:0] remainder;
    reg [3:0] cnt;
    reg start_cnt;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            shift_reg <= 0;
            neg_divisor <= 0;
            quotient <= 0;
            remainder <= 0;
            cnt <= 0;
            start_cnt <= 0;
            res_valid <= 0;
        end else begin
            if (opn_valid && !res_valid) begin
                shift_reg <= {dividend[7], dividend} << 1;
                neg_divisor <= ~{divisor[7], divisor} + 1;
                cnt <= 1;
                start_cnt <= 1;
            end

            if (start_cnt) begin
                if (cnt == 8) begin
                    cnt <= 0;
                    start_cnt <= 0;
                    res_valid <= 1;
                    result <= {remainder, quotient};
                end else begin
                    if (shift_reg >= neg_divisor) begin
                        shift_reg <= shift_reg - neg_divisor;
                        quotient[cnt] <= 1;
                    end else begin
                        quotient[cnt] <= 0;
                    end

                    shift_reg <= shift_reg << 1;
                    cnt <= cnt + 1;
                end
            end
        end

        if (rst) begin
            res_valid <= 0;
        end else if (cnt == 8) begin
            res_valid <= 1;
        end else if (res_valid && res_ready) begin
            res_valid <= 0;
        end
    end

    assign result = {remainder, quotient};
endmodule

