<module id="div_8bit">
    <description>Implement a simplified radix-2 divider on 8-bit signed or unsigned integers. Accepts a dividend and a divisor as inputs and provides a 16-bit result containing both the quotient and the remainder. Supports both signed and unsigned division operations.</description>
    <ports>
        <input id="clk">Clock signal used for synchronous operation.</input>
        <input id="rst">The reset signal to initialize or reset the module.</input>
        <input id="sign">1-bit indicates if the operation is signed (1) or unsigned (0).</input>
        <input id="dividend" width_description="[7:0]">8-bit input signal representing the dividend for division.</input>
        <input id="divisor" width_description="[7:0]">8-bit input signal representing the divisor for division.</input>
        <input id="opn_valid">1-bit indicates that a valid operation request is present.</input>
        <input id="res_ready">1-bit indicates that the 16-bit output result has already been acknowledged.</input>
        <output id="res_valid">1-bit output signal indicating the result is valid and ready.</output>
        <output id="result" width_description="[15:0]">16-bit the output containing the remainder in the upper 8 bits and the quotient in the lower 8 bits.</output>
    </ports>
    <parameter_description>
        <state name="IDLE" value="2'b00"/>
        <state name="DIVIDE" value="2'b01"/>
        <state name="DONE" value="2'b10"/>
    </parameter_description>
    <logic_description type="sequential_logic">
        <reg id="shift_reg" width="9" init_value="0">Shift register for storing partial results.</reg>
        <reg id="neg_divisor" width="9" init_value="0">Negative divisor for subtraction.</reg>
        <reg id="quotient" width="8" init_value="0">Quotient of the division.</reg>
        <reg id="remainder" width="8" init_value="0">Remainder of the division.</reg>
        <reg id="cnt" width="4" init_value="0">Counter for tracking iterations.</reg>
        <reg id="start_cnt" width="1" init_value="0">Flag to indicate start of counting.</reg>
        <reg id="res_valid_reg" width="1" init_value="0">Register for managing result validity.</reg>
    </logic_description>
    <implementation>
        // Initialize registers on reset
        always @(posedge clk or posedge rst) begin
            if (rst) begin
                shift_reg <= 0;
                neg_divisor <= 0;
                quotient <= 0;
                remainder <= 0;
                cnt <= 0;
                start_cnt <= 0;
                res_valid_reg <= 0;
            end else begin
                if (opn_valid && !res_valid_reg) begin
                    // Save inputs
                    shift_reg <= {dividend[7], dividend} << 1; // Shift dividend left by 1
                    neg_divisor <= ~{divisor[7], divisor} + 1; // Negate divisor
                    cnt <= 1;
                    start_cnt <= 1;
                end

                if (start_cnt) begin
                    if (cnt == 8) begin
                        // Division complete
                        cnt <= 0;
                        start_cnt <= 0;
                        res_valid_reg <= 1;
                        result <= {remainder, quotient};
                    end else begin
                        // Perform subtraction
                        if (shift_reg >= neg_divisor) begin
                            shift_reg <= shift_reg - neg_divisor;
                            quotient[cnt] <= 1;
                        end else begin
                            quotient[cnt] <= 0;
                        end

                        // Shift left
                        shift_reg <= shift_reg << 1;
                        cnt <= cnt + 1;
                    end
                end
            end

            // Manage result validity
            if (rst) begin
                res_valid_reg <= 0;
            end else if (cnt == 8) begin
                res_valid_reg <= 1;
            end else if (res_valid_reg && res_ready) begin
                res_valid_reg <= 0;
            end
        end

        // Assign outputs
        assign res_valid = res_valid_reg;
        assign result = {remainder, quotient};
    </implementation>
</module>
